var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"서면을 주고받긴 했지만, 실제로 뵙는 건 처음이군요. 시스터.","JPN":"書面は交わしましたが、実際会うのは初めてですね。シスター。","ENG":"Though we have exchanged letters before, I believe this is the first time we meet in person, Sister.","TWN":"雖然彼此有書信往來，但這還是第一次見到本人呢，姊妹。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"비블리데 루체 자매님이시군요.","JPN":"シスター・ビブリデ・ルーチェですね。","ENG":"It's you, Sister Biblide Luce.","TWN":"原來是布莉黛·露契姊妹。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……감사합니다. 자매님.","JPN":"……ありがとうございます、シスター・ルーチェ。","ENG":"Thank you, Sister...","TWN":"……謝謝你。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님이 손 써주시지 않았다면, 루퍼 자매님에 대한 종교 재판이 벌어졌을 거예요.","JPN":"あなたが手を尽くしてくれなかったら、シスター・ルーパーへの宗教裁判が始まっていたことでしょう。","ENG":"If it wasn’t for you, the Inquisition would have sided against Sister Looper.","TWN":"要不是你出手，洛珀姊妹很可能會受到宗教裁判。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그리고 헤밍턴 형제님의 일도 감사드려요.","JPN":"そしてハミントン兄弟のことも感謝しますわ。","ENG":"And please thank Brother Hammington for me.","TWN":"海明頓弟兄的事也很謝謝你。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님이 없었다면, 그 분은…….","JPN":"シスター・ルーチェがいなかったら、あの方は……","ENG":"If you weren't there to help... he...","TWN":"要不是你，他……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해드리죠, 시스터 넬슨.","JPN":"喜んで訂正いたします、シスターネルソン。","ENG":"I would be more than happy to rephrase, Sister Nelson.","TWN":"我要更正一下，尼爾森姊妹。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 제 목적을 위해 성무 SI3E를 조사하고 있을 뿐입니다.","JPN":"私は自分の目的のために聖務SI3Eを調査しているだけです。","ENG":"I was reading Sacred Mission SI3E for personal reasons.","TWN":"我調查聖務SI3E有我私人的原因，"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"딱히 감사 인사를 받을 이유는 없죠.","JPN":"とりたてて感謝される理由はありません。","ENG":"There is no need to thank me.","TWN":"所以沒理由接受你的道謝。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 최소한 자매님의 질문에 성실히 답하는 것이 그 감사의 표시가 되겠네요.","JPN":"でしたら、あなたの質問に真面目に答えることがせめてもの感謝のしるしになるでしょう。","ENG":"Then, I believe answering your questions truthfully will be the least I can do as a thanks for what you did for us.","TWN":"那至少讓我誠實地回答你的問題，以示感謝吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋습니다. 제가 열람한 참고인 중에 가장 협조적이시군요.","JPN":"ありがとうございます。私が閲覧した参考人の中でもっとも協力的ですね。","ENG":"Very well. Among the witnesses I have browsed you are the most cooperative one.","TWN":"好，你是我讀過的證人中最配合的呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아시다시피 베네딕트 콘스탄틴은 성무 SI3E를 계기로 완전히 변절했습니다.","JPN":"ご存じでしょうが、ベネディクト・コンスタンティンは聖務SI3Eをきっかけに完全に宗旨替えをしてしまいました。","ENG":"As you may be aware, Benedict Constantine has fully  changed sides after Sacred Mission SI3E.","TWN":"你應該知道，本尼迪克特·康斯坦丁藉著聖務SI3E叛變一事。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대략적인 정황은 읽어냈지만 여전히 의문이 남아있죠.","JPN":"大体の状況は読めましたが、依然として疑問が残っています。","ENG":"I read the rough outline, but there are still some questions that need to be answered.","TWN":"雖然我已經讀出一個脈絡，但還是有些疑問。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하지만 괜찮을까요?","JPN":"でも大丈夫でしょうか？","ENG":"Are you sure this will be all right?","TWN":"可是沒關係嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님께 구조되기 전까지 저는 신부님의 행동을…….","JPN":"シスター・ルーパーが救助されるまで、私は神父様の行動を……","ENG":"Until I was rescued by Sister Looper...","TWN":"在洛珀姊妹把我救出來之前，我對神父的下落……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결론을 읽어내는 건 접니다. 그건 당신이 걱정할 문제가 아니죠.","JPN":"結論を読み取るのは私です。それはあなたが心配する問題ではありません。","ENG":"You have nothing to be concerned about. I will be the one who reads the end.","TWN":"結論是由我來讀的，不需要你費心。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"좋아요, 자매님.","JPN":"わかりました、シスター・ルーチェ。","ENG":"Okay, Sister.","TWN":"好的，姊妹。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};